#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            int h;
            scanf("%d", &h);
            if (h > K) ++cnt;
        }
        printf("%d\n", cnt);
    }
    return 0;
}

